UPDATE words SET example_en_2 = 'The result surprised everyone at the stadium.', example_ko_2 = '결과는 경기장에 있던 모든 사람을 놀라게 했어요.', example_en_3 = 'She accepted the result without complaint.', example_ko_3 = '그녀는 불평 없이 결과를 받아들였어요.', example_en_4 = 'The result will affect which team goes through.', example_ko_4 = '결과에 따라 어떤 팀이 통과할지 결정돼요.', example_en_5 = 'He checked the results online after the event.', example_ko_5 = '그는 대회 후에 온라인으로 결과를 확인했어요.' WHERE id = 'w_sports_A2_33';
UPDATE words SET example_en_2 = 'She sprinted to the finish line ahead of everyone.', example_ko_2 = '그녀는 모든 선수를 앞질러 결승선까지 전력 질주했어요.', example_en_3 = 'He sprinted to block the opponent''s shot.', example_ko_3 = '그는 상대방의 슛을 막으려고 전력 질주했어요.', example_en_4 = 'A short sprint at the end of training builds speed.', example_ko_4 = '훈련 마지막에 짧은 전력 질주는 속도를 키워요.', example_en_5 = 'The sprinters lined up at the starting block.', example_ko_5 = '단거리 선수들이 출발 블록에 줄을 섰어요.' WHERE id = 'w_sports_A2_34';
UPDATE words SET example_en_2 = 'She won a gold medal at the national games.', example_ko_2 = '그녀는 전국 대회에서 금메달을 땄어요.', example_en_3 = 'He wore his medal proudly on the podium.', example_ko_3 = '그는 시상대에서 자랑스럽게 메달을 달았어요.', example_en_4 = 'The medal ceremony took place after the final.', example_ko_4 = '메달 시상식은 결승전 이후에 열렸어요.', example_en_5 = 'Winning a medal is the dream of every athlete.', example_ko_5 = '메달을 따는 것은 모든 선수의 꿈이에요.' WHERE id = 'w_sports_A2_35';
